            className="border-4 border-white rounded-full shadow-lg"
            style={{
              width: `${CROP_PREVIEW_SIZE}px`,
              height: `${CROP_PREVIEW_SIZE}px`,
            }}
          />
        </div>

        {/* Sliders */}
        <div className="space-y-4 bg-black/20 p-4 rounded-lg mb-6">
          <div>
            <label className="text-white/80 text-xs block mb-2">
              Move Left/Right
            </label>
            <input
              type="range"
              min="-100"
              max="100"
              value={cropState.offsetX}
              onChange={(e) =>
                setCropState({ ...cropState, offsetX: parseInt(e.target.value) })
              }
              className="w-full"
            />
          </div>

          <div>
            <label className="text-white/80 text-xs block mb-2">
              Move Up/Down
            </label>
            <input
              type="range"
              min="-100"
              max="100"
              value={cropState.offsetY}
              onChange={(e) =>
                setCropState({ ...cropState, offsetY: parseInt(e.target.value) })
              }
              className="w-full"
            />
          </div>

          <div>
            <label className="text-white/80 text-xs block mb-2">Zoom</label>
            <div className="flex gap-2">
              <button
                onClick={() =>
                  setCropState({
                    ...cropState,
                    zoom: Math.max(0.5, cropState.zoom - 0.2),
                  })
                }
                className="flex-1 bg-purple-500 hover:bg-purple-600 text-white py-1 rounded transition"
              >
                −
              </button>
              <span className="flex-1 text-center text-white text-sm">
                {cropState.zoom.toFixed(1)}x
              </span>
              <button
                onClick={() =>
                  setCropState({
                    ...cropState,
                    zoom: Math.min(3, cropState.zoom + 0.2),
                  })
                }
                className="flex-1 bg-purple-500 hover:bg-purple-600 text-white py-1 rounded transition"
              >
                +
              </button>
            </div>
          </div>
        </div>

        {/* Controls */}
        <div className="flex gap-3">
          <button
            onClick={handleConfirm}
            className="flex-1 bg-green-500 hover:bg-green-600 text-white font-bold py-2 rounded-lg transition"
          >
            ✓ Use This
          </button>
          <button
            onClick={onCancel}
            className="flex-1 bg-red-500 hover:bg-red-600 text-white font-bold py-2 rounded-lg transition"
          >
            ✕ Change
          </button>
        </div>
      </div>
    </div>
  );
};

