    const playerRank = playerRecordIndex >= 0 ? playerRecordIndex + 1 : null;

    return { leaderboard, playerRank, playerRecord };
  } catch (error) {
    return {
      leaderboard: [],
      playerRank: null,
      playerRecord: null,
      error: String(error),
    };
  }
