  const handleRestart = useCallback(() => {
    setGameState((prev) => ({
      ...prev,
      phase: 'READY',
      score: 0,
      error: null,
    }));
  }, []);

  /**
   * Upload new image
   */
  const handleUploadNew = useCallback(() => {
    setGameState((prev) => ({
      ...prev,
