          {gameState.phase === 'READY' && playerImageRef.current && (
            <div className="space-y-4">
              <div className="flex justify-center mb-4">
                <img
                  src={previewImageSrc || ''}
                  alt="Your avatar"
                  className="w-20 h-20 rounded-full border-4 border-white shadow-lg"
                />
              </div>
