                <p className="text-white/90">
                  Your Score: <span className="text-3xl font-bold text-yellow-300">{gameState.score}</span>
                </p>
                {gameState.score > gameState.highScore && (
                  <p className="text-green-300 font-bold mt-2">🎉 New Personal Best!</p>
                )}
              </div>

              {gameState.error && (
                <div className="bg-red-500/30 rounded-lg p-3 text-red-200 text-sm">
                  {gameState.error}
                </div>
              )}

              <input
                type="text"
                placeholder="Enter your name"
                maxLength={50}
                value={gameState.playerName}
                onChange={(e) =>
                  setGameState((prev) => ({
                    ...prev,
                    playerName: e.target.value,
